mapper.select:
SELECT j.id, j.title, j.min_salary AS minSalary, j.max_salary AS maxSalary, j.headcount AS headcount, j.work_location AS workLocation, j.district, j.experience, j.degree, j.tags, j.create_time AS createTime,
-- 【优化】公司名逻辑：只取企业表的公司名，如果没有，显示'未认证企业' -- 不再使用用户昵称填充公司名，避免出现“公司名=人名”的尴尬情况 COALESCE(m.company_name, '未认证企业') AS companyName, COALESCE(m.company_logo, u.avatar) AS companyLogo,
-- 发布者信息 COALESCE(u.nickname, u.username, '招聘官') AS publisherName, u.avatar AS publisherAvatar FROM job_post j LEFT JOIN sys_user u ON j.merchant_id = u.id LEFT JOIN merchant_profile m ON u.id = m.user_id WHERE j.status = 1 AND j.audit_status = 1
AND (j.title LIKE CONCAT('%', #{keyword}, '%') OR COALESCE(m.company_name, '未认证企业') LIKE CONCAT('%', #{keyword}, '%'))
AND j.category_id = #{categoryId}
AND j.degree = #{degree}
AND j.experience = #{experience}
AND (j.work_location LIKE CONCAT('%', #{location}, '%') OR j.district LIKE CONCAT('%', #{location}, '%'))
AND j.work_location = #{city}
AND j.district = #{district}
AND j.max_salary >= #{minSalary}
AND j.min_salary <= #{maxSalary}
AND m.industry = #{industry}
AND m.scale = #{scale}
AND m.financing = #{financing}
AND ( j.degree IS NULL OR j.degree = '' OR j.degree = '不限' OR ( CASE j.degree WHEN '大专' THEN 1 WHEN '本科' THEN 2 WHEN '硕士' THEN 3 WHEN '博士' THEN 4 ELSE 0 END <= CASE #{smartDegreeCap} WHEN '大专' THEN 1 WHEN '本科' THEN 2 WHEN '硕士' THEN 3 WHEN '博士' THEN 4 ELSE 0 END ) )
AND ( j.experience IS NULL OR j.experience = '' OR j.experience = '不限' OR ( CASE j.experience WHEN '应届生' THEN 1 WHEN '1-3年' THEN 2 WHEN '3-5年' THEN 3 WHEN '5-10年' THEN 4 WHEN '10年以上' THEN 5 ELSE 0 END <= CASE #{smartExperienceCap} WHEN '应届生' THEN 1 WHEN '1-3年' THEN 2 WHEN '3-5年' THEN 3 WHEN '5-10年' THEN 4 WHEN '10年以上' THEN 5 ELSE 0 END ) )
AND (j.max_salary IS NULL OR j.max_salary >= #{smartMinSalary})
ORDER BY
j.max_salary DESC, j.min_salary DESC
j.min_salary ASC, j.max_salary ASC
j.view_count DESC
j.create_time DESC

SELECT
    j.*,
    c.category_name AS categoryName
FROM job_post j
LEFT JOIN job_category c ON j.category_id = c.id
WHERE j.merchant_id = #{merchantId}

    AND j.status = #{status}


    AND j.audit_status = #{auditStatus}

ORDER BY j.create_time DESC
